// frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer, useMap } from "react-leaflet";
import "leaflet/dist/leaflet.css";

/**
 * HYBRID RADAR
 * - Keeps your existing base precip tiles (customize BASE_URL to your old one)
 * - Adds a RainViewer overlay with a slider & play button
 * - Toggle "Forecast" to include future frames
 */

const BASE_URL = "https://tile.openstreetmap.org/{z}/{x}/{y}.png"; 
// ^^^ replace with your PREVIOUS radar precipitation tiles if you had a custom source earlier.
// e.g. if you used a weather tile provider, put that URL back here so precip looks the same.

function RainViewerOverlay({ timestamp, visible }) {
  const map = useMap();
  const layerRef = useRef(null);

  useEffect(() => {
    // clear old
    if (layerRef.current) {
      map.removeLayer(layerRef.current);
      layerRef.current = null;
    }
    if (!timestamp || !visible) return;

    const url = `https://tilecache.rainviewer.com/v2/radar/${timestamp}/256/{z}/{x}/{y}/2/1_1.png`;
    const layer = new window.L.TileLayer(url, {
      opacity: 0.85,
      zIndex: 500,
      maxZoom: 12,
      tileSize: 256,
    });
    layer.addTo(map);
    layerRef.current = layer;

    return () => {
      if (layerRef.current) {
        map.removeLayer(layerRef.current);
        layerRef.current = null;
      }
    };
  }, [timestamp, visible, map]);

  return null;
}

export default function Radar({
  center = [33.749, -84.388],
  zoom = 6,
  height = 320,
  className = "",
}) {
  const [frames, setFrames] = useState([]); // [{time, type: "past" | "future"}]
  const [idx, setIdx] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [showFuture, setShowFuture] = useState(true);

  // load RainViewer frames
  useEffect(() => {
    let cancel = false;
    (async () => {
      try {
        const res = await fetch("https://tilecache.rainviewer.com/api/maps.json");
        const data = await res.json();
        if (cancel) return;
        const past = (data?.past || []).map((t) => ({ time: t, type: "past" }));
        const future = (data?.nowcast || []).map((t) => ({ time: t, type: "future" }));
        const all = [...past, ...future];
        setFrames(all);
        setIdx(all.length - 1); // latest
      } catch (e) {
        console.error("RainViewer frames error:", e);
      }
    })();
    return () => { cancel = true; };
  }, []);

  // filter frames by future toggle
  const visibleFrames = useMemo(
    () => frames.filter((f) => showFuture || f.type !== "future"),
    [frames, showFuture]
  );

  const lastIdx = Math.max(visibleFrames.length - 1, 0);
  const safeIdx = Math.min(Math.max(idx, 0), lastIdx);
  const ts = visibleFrames[safeIdx]?.time;

  // autoplay
  useEffect(() => {
    if (!playing || visibleFrames.length === 0) return;
    const id = setInterval(() => {
      setIdx((i) => (i + 1) % visibleFrames.length);
    }, 600);
    return () => clearInterval(id);
  }, [playing, visibleFrames.length]);

  // only show overlay when not exactly on the latest "now" frame
  const showOverlay = Boolean(ts) && !(safeIdx === lastIdx);

  return (
    <div className={`relative w-full ${className}`} style={{ height }}>
      <MapContainer center={center} zoom={zoom} style={{ height: "100%", width: "100%" }}>
        {/* YOUR old precip base tiles go here */}
        <TileLayer url={BASE_URL} attribution="&copy; OpenStreetMap contributors" />
        {/* RainViewer radar overlay for past/future frames */}
        <RainViewerOverlay timestamp={ts} visible={showOverlay} />
      </MapContainer>

      {/* Controls */}
      <div className="absolute left-2 bottom-2 flex flex-wrap gap-2 items-center rounded-xl bg-black/70 text-white px-3 py-2">
        <button
          className="px-2 py-1 rounded bg-white/10 hover:bg-white/20"
          onClick={() => setPlaying((p) => !p)}
        >
          {playing ? "Pause" : "Play"}
        </button>
        <input
          type="range"
          min={0}
          max={lastIdx}
          value={safeIdx}
          onChange={(e) => setIdx(parseInt(e.target.value, 10))}
          style={{ width: 180 }}
        />
        <label className="flex items-center gap-1 text-xs">
          <input
            type="checkbox"
            checked={showFuture}
            onChange={(e) => setShowFuture(e.target.checked)}
          />
          Forecast
        </label>
        <div className="text-xs opacity-80">
          {visibleFrames[safeIdx]?.type === "future" ? "Future" : "Past/Now"}
        </div>
      </div>
    </div>
  );
}
